import { CardHeader, IconButton, Typography } from '@material-ui/core'
import { MoreVert } from '@material-ui/icons'
import React from 'react'

export default function Card({ subject }) {
  return (
    <div>
        <Typography>
        <Card>
            <CardHeader 
                action={
                    <IconButton>
                        <MoreVert />
                    </IconButton>
                }
            />
        </Card>
        </Typography>
    </div>
  )
}
